<template>
  <section class="parallax-group">
      <div class="background_image"></div>
      <div class="middle_image"></div>
      <div class="foreground_image" style="display: flex; align-items: center; justify-content: center;">

        <div class="content-box" style="margin: 0; margin-top: -15vh;">
          <h1 style="text-align: center;">Hi! I'm Matt McAdams</h1>
          <p style="text-align: center;">Graphic designer, web developer, and creative problem solver</p>

          <div class="grid">
            <a class="button" href="https://github.com/MattMcAdams/" target="_blank" style="display: block; text-align: center;">GitHub</a>
            <a class="button" href="/portfolio/" style="display: block; text-align: center;">Portfolio</a>
          </div>
        </div>

	    <div class="parallax_mask"></div>
    </div>
  </section>
</template>

<style lang="scss">

.parallax-group {
  position: relative;
  height: 90vh;
  z-index: -1;
}
.background_image,
.middle_image,
.foreground_image {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  background-size: cover;
  background-position: bottom;
}

@media (hover: hover) {

  #app {
    perspective: 2px;
    height: 100vh;
    overflow-x: hidden;
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    perspective-origin-x: 100%;
  }
  .parallax-group,
  main {
    position: relative;
    transform-style: preserve-3d;
  }
  .background_image {
    transform-origin: 0,0;
    transform: translateZ(-1px) scale(1.5);
    background-image: var(--back-layer);
  }
  .middle_image {
    transform-origin: 0,0;
    transform: translateZ(-0.5px) scale(1.3);
    background-image: var(--middle-layer);
  }
  .foreground_image {
    transform-origin: 0,0;
    transform: translateZ(0px) scale(1);
    background-image: var(--front-layer);
  }
  .parallax_mask {
    position: absolute;
    right: 0;
    bottom: -200px;
    left: 0;
    height: 200px;
    transform-origin-x: 100%;
    transform: translateZ(0) scale(1);
    background-color: var(--bg-color);
  }
}

